import React, { useEffect, useState } from 'react';
import StationSearch from './components/StationSearch';
import ScheduleList from './components/ScheduleList';
import { getStationSchedule, loadStationsList } from './api/yandexRasp';

function App() {
  const [selectedStation, setSelectedStation] = useState(null);
  const [schedule, setSchedule] = useState([]);
  const [stations, setStations] = useState([]);
  const [loading, setLoading] = useState(false);

  // Загружаем станции при старте
  useEffect(() => {
    loadStationsList().then(stationsList => {
      setStations(stationsList);
      window.__stationsCache = stationsList; // кэш для поиска
      console.log(`Загружено ${stationsList.length} станций`);
    });
  }, []);

  // Загрузка расписания станции
  const loadStationSchedule = async (station) => {
    setLoading(true);
    try {
      const data = await getStationSchedule(station.code);
      setSchedule(data);
      setSelectedStation(station);
    } catch (err) {
      alert('Ошибка загрузки расписания');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container-fluid py-3">
      <h1 className="h4 mb-3">⚡ Прибывалка: Электрички</h1>
      
      {/* Поиск станции */}
      <StationSearch onSelect={loadStationSchedule} />
      
      {/* Расписание */}
      {loading && <div className="alert alert-info">⏳ Загрузка...</div>}
      
      {selectedStation && (
        <ScheduleList 
          segments={schedule} 
          title={`🚉 Расписание: ${selectedStation.title}`} 
        />
      )}
      
      {selectedStation && schedule.length === 0 && !loading && (
        <div className="alert alert-warning">
          Нет рейсов для станции {selectedStation.title}
        </div>
      )}
    </div>
  );
}

export default App;
